<template>
    <div>
        <div id="map" style="width: 100%; height: 500px;"></div>
        <div id="dummyArea"></div>
        <button @click="add()">add</button><br>
    </div>
</template>


<script>

    import daumMap from "daum-map-wrap";

    export default {
        name: "Map",
        created() {
            this.init();
            this.markers = []; // 마커를 담을 배열
        },
        methods: {
            data(){

            },
            init() {
                daumMap(this.daumKey, "drawing", "services", "clusterer").then(maps => {
                    this.maps = maps;
                    this.geocoder = new this.maps.services.Geocoder();
                    this.places = new this.maps.services.Places();
                    // 지도를 초기화함.
                    this.initMap();
                    this.eventBind();
                });
            },
            initMap() {
                let lat = 37.566826005485716;
                let lng = 126.9786567859313;
                let latLng = new this.maps.LatLng(lat, lng);
                let options = {
                    center: latLng,
                    level: 8,
                    disableDoubleClick: true,
                    draggable: true,
                    scrollwheel: true
                };
                this.map = new this.maps.Map(document.getElementById('map'), options);
                this.initMetro();
            },
            initMetro() {
                this.axios("../../static/json/codeGeo_metro.json")
                    .then((res) => {
                        let metroData = res.data;

                        _.each(metroData, (item) => {
                           _.each(item.codeList, (i) => {
                               let marker = new this.maps.Marker({
                                   position: new this.maps.LatLng(i.lat, i.lng)
                               });
                               marker.setMap(this.map);
                               this.markers.push(marker);
                           });
                        });

                    });
            },
            eventBind() {
            },
            mapIdle() {
            },
            mapClick(e) {
            },
            initClusterer() {
            },
            setClusterer() {
            },
        }
    }
</script>

<style scoped>

</style>



